#!/usr/bin/env bun
import { mkdir, writeFile } from "node:fs/promises";
import { resolve } from "node:path";
import openapiTS, { astToString } from "openapi-typescript";

const SPEC_PATH = resolve(import.meta.dir, "..", "specs", "openapi.json");
const OUT_DIR = resolve(import.meta.dir, "..", "packages", "tochka-sdk", "src", "_generated");
const OUT_FILE = resolve(OUT_DIR, "schema.d.ts");
const META_FILE = resolve(OUT_DIR, "meta.ts");

const HEADER = `/**
 * AUTO-GENERATED by tools/gen.ts from specs/openapi.json.
 * Do not edit directly — run \`bun run gen\` instead.
 */
`;

async function main() {
	console.log(`→ Generating types from ${SPEC_PATH}`);

	const ast = await openapiTS(new URL(`file://${SPEC_PATH}`), {
		alphabetize: true,
		exportType: true,
		rootTypes: true,
		immutable: false,
	});
	const body = astToString(ast);

	await mkdir(OUT_DIR, { recursive: true });
	await writeFile(OUT_FILE, HEADER + body);
	console.log(`✓ Wrote ${OUT_FILE}`);

	const spec = (await Bun.file(SPEC_PATH).json()) as {
		info: { title: string; version: string };
		servers: { url: string; description?: string }[];
	};
	const prodServer = spec.servers.find((s) => /uapi/.test(s.url))?.url ?? spec.servers[0]?.url;
	const sandboxServer =
		spec.servers.find((s) => /sandbox/.test(s.url))?.url ?? spec.servers[0]?.url;

	const meta = `${HEADER}
export const TOCHKA_API_VERSION = ${JSON.stringify(spec.info.version)} as const;
export const TOCHKA_API_TITLE = ${JSON.stringify(spec.info.title)} as const;
export const TOCHKA_BASE_URL_PROD = ${JSON.stringify(prodServer)} as const;
export const TOCHKA_BASE_URL_SANDBOX = ${JSON.stringify(sandboxServer)} as const;
`;
	await writeFile(META_FILE, meta);
	console.log(`✓ Wrote ${META_FILE} (API version: ${spec.info.version})`);
}

await main();
